import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult, ModelProvider, MarketType } from "../types";

const quantVaneSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    scan_time: { type: Type.STRING },
    overall_cluster_intensity: { type: Type.NUMBER },
    market_environment: { type: Type.STRING },
    dominant_factor: { type: Type.STRING },
    hot_clusters: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          sector: { type: Type.STRING },
          intensity: { type: Type.NUMBER },
          reason: { type: Type.STRING }
        },
        required: ["sector", "intensity", "reason"]
      }
    },
    candidates: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          code: { type: Type.STRING },
          cluster_score: { type: Type.NUMBER },
          strategy_tag: { type: Type.STRING, enum: ['HighFreq', 'TrendFollowing', 'Arbitrage'] },
          synergy_logic: { type: Type.STRING },
          volatility_match: { type: Type.STRING },
          action_level: { type: Type.STRING, enum: ['Follow', 'Observe', 'Avoid'] }
        },
        required: ["name", "code", "cluster_score", "strategy_tag", "synergy_logic", "action_level"]
      }
    },
    risk_warning: { type: Type.STRING }
  },
  required: ["scan_time", "overall_cluster_intensity", "market_environment", "hot_clusters", "candidates", "risk_warning"]
};

export const fetchQuantClusterAnalysis = async (market: MarketType, apiKey: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN');

  const prompt = `
    【指令：全量量化资金抱团审计雷达】
    今日日期: ${dateStr}。作为资深量化对冲基金经理，利用 googleSearch 检索 ${market} 市场中【量化资金 (Quantitative Funds)】的最新动向。

    [重点审计逻辑]：
    1. **识别抱团标的**：寻找那些在近 3 个交易日内，股价波动率、成交量变化呈现极高同步性（量化抱团特征）的标的。
    2. **策略偏好挖掘**：分析当前量化机构是在进行“高频套利”、“趋势跟随”还是“波动率对冲”。
    3. **板块共振**：哪些板块出现了明显的量化资金合力？(如：昨日是半导体，今日是否切换到AI机器人？)
    4. **风险水位**：判断当前抱团是否过于拥挤 (Overcrowded)，是否存在崩塌风险。

    输出必须为严格 JSON 格式。
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: quantVaneSchema
    }
  });

  const parsed = JSON.parse(response.text || "{}");
  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    quantVaneData: parsed,
    market
  };
};

