import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult, ModelProvider, MarketType } from "../types";

const quantVaneSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    scan_time: { type: Type.STRING, description: "扫描执行的具体时间点" },
    overall_cluster_intensity: { type: Type.NUMBER, description: "全市场量化抱团的总强度评分 (0-100)" },
    market_environment: { type: Type.STRING, description: "当前市场环境一句话定性 (如：缩量震荡中的局部抱团)" },
    dominant_factor: { type: Type.STRING, description: "当前主导量化模型的核心因子 (如：流动性、波动率、小市值)" },
    hot_clusters: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          sector: { type: Type.STRING, description: "抱团板块名称" },
          intensity: { type: Type.NUMBER, description: "板块抱团强度" },
          reason: { type: Type.STRING, description: "抱团背后的底层逻辑" }
        },
        required: ["sector", "intensity", "reason"]
      }
    },
    candidates: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          code: { type: Type.STRING },
          cluster_score: { type: Type.NUMBER, description: "个股抱团分" },
          strategy_tag: { type: Type.STRING, enum: ['高频套利', '趋势跟随', '波动对冲'], description: "量化策略类型" },
          synergy_logic: { type: Type.STRING, description: "资金合力具体表现" },
          volatility_match: { type: Type.STRING, description: "量价匹配度" },
          action_level: { type: Type.STRING, enum: ['立即跟随', '动态观察', '坚决回避'], description: "建议操作级别" }
        },
        required: ["name", "code", "cluster_score", "strategy_tag", "synergy_logic", "action_level"]
      }
    },
    risk_warning: { type: Type.STRING, description: "针对当前抱团状态的风险警示语" }
  },
  required: ["scan_time", "overall_cluster_intensity", "market_environment", "hot_clusters", "candidates", "risk_warning"]
};

export const fetchQuantClusterAnalysis = async (market: MarketType, apiKey: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN');

  const prompt = `
    【指令：全量量化资金抱团审计雷达】
    今日日期: ${dateStr}。作为首席量化策略师，请利用 googleSearch 检索 ${market} 市场中【量化基金 (Quant Funds)】的最新异常动向。

    [重点审计逻辑]：
    1. **识别抱团特征**：寻找那些在近 3 个交易日内，股价波动率、成交量变化呈现“极高同步性”的板块和标的（这是量化模型集体触发买入的信号）。
    2. **策略偏好挖掘**：分析当前主流算法是在进行“高频套利”、“趋势跟随”还是基于基差的“波动对冲”。
    3. **资金合力评估**：哪些标的出现了明显的“无声合力”？(例如：换手率异常稳定但重心不断抬高)。
    4. **拥挤度预警**：判断当前抱团是否已达极致 (Overcrowded)，是否存在模型集体止损导致的踩踏风险。

    [输出要求]：
    1. 必须使用中文回答所有描述字段。
    2. 严格遵守提供的 JSON Schema 格式。
    3. 重点关注震荡行情下的避险抱团方向。
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: quantVaneSchema
    }
  });

  const parsed = JSON.parse(response.text || "{}");
  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    quantVaneData: parsed,
    market
  };
};

