import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult, ModelProvider, MarketType } from "../types";

const quantVaneSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    scan_time: { type: Type.STRING },
    overall_mood: { type: Type.STRING },
    quant_boarding_list: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          code: { type: Type.STRING },
          net_amount: { type: Type.STRING },
          direction: { type: Type.STRING, enum: ['Buy', 'Sell'] },
          intensity_score: { type: Type.NUMBER },
          logic: { type: Type.STRING }
        },
        required: ["name", "code", "net_amount", "direction", "logic"]
      }
    },
    quant_grabbing_list: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          code: { type: Type.STRING },
          net_amount: { type: Type.STRING },
          direction: { type: Type.STRING, enum: ['Buy', 'Sell'] },
          intensity_score: { type: Type.NUMBER },
          logic: { type: Type.STRING }
        },
        required: ["name", "code", "net_amount", "direction", "logic"]
      }
    },
    quant_swing_list: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          code: { type: Type.STRING },
          net_amount: { type: Type.STRING },
          direction: { type: Type.STRING, enum: ['Buy', 'Sell'] },
          intensity_score: { type: Type.NUMBER },
          logic: { type: Type.STRING }
        },
        required: ["name", "code", "net_amount", "direction", "logic"]
      }
    },
    risk_warning: { type: Type.STRING }
  },
  required: ["scan_time", "overall_mood", "quant_boarding_list", "quant_grabbing_list", "quant_swing_list", "risk_warning"]
};

export const fetchQuantClusterAnalysis = async (market: MarketType, apiKey: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN');

  const prompt = `
    【硬核指令：量化基金席位全量审计】
    今日日期: ${dateStr}。作为首席量化席位研究员，请利用 googleSearch 检索 ${market} 市场中最近 1-3 个交易日的【龙虎榜 (Dragon-Tiger List)】。

    [重点检索与分类逻辑]：
    1. **量化基金总榜**：识别在龙虎榜买入/卖出席位中出现“量化基金”、“机构专用（量化性质）”或“知名量化大户”的标的。
    2. **量化打板**：专门提取那些今日涨停且量化席位净买入额前 10 的标的。
    3. **量化抢筹**：提取那些非涨停、但量化席位在大单买入占比显著提升、呈现“吸筹”特征的标的。
    4. **数据真值**：净买入额必须对齐最新的龙虎榜快报数据（如：xxx万，xxx亿）。

    [输出要求]：
    - 将结果严格分类为：quant_boarding_list (量化打板), quant_grabbing_list (量化抢筹), quant_swing_list (量化波段/基金榜)。
    - 必须包含每个标的的【净买入/卖出额】（参考截图：净买 9059.9万）。
    - 语言全中文，严格遵守 JSON Schema。
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: quantVaneSchema
    }
  });

  const parsed = JSON.parse(response.text || "{}");
  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    quantVaneData: parsed,
    market
  };
};

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ModelProvider, MarketType, AnalysisResult, QuantVaneStock } from '../types';
import { fetchQuantClusterAnalysis } from '../services/quantService';
import { Radio, Loader2, Search, ArrowRight, Zap, Flame, ShieldCheck, Activity, UserCheck, ShieldAlert, Target, Info, Sparkles, TrendingUp, Gauge, RefreshCw, BarChart3, Globe, ChevronRight } from 'lucide-react';

interface QuantVaneProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: any;
  onOpenSettings: () => void;
}

export const QuantVane: React.FC<QuantVaneProps> = ({ currentModel, currentMarket, settings, onOpenSettings }) => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [elapsed, setElapsed] = useState(0);

  useEffect(() => {
    let interval: any;
    if (loading) {
      setElapsed(0);
      interval = setInterval(() => setElapsed(p => p + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleScan = async () => {
    const apiKey = settings.geminiKey || process.env.API_KEY;
    if (!apiKey) {
      onOpenSettings();
      return;
    }
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await fetchQuantClusterAnalysis(currentMarket, apiKey);
      setResult(data);
    } catch (err: any) {
      setError(err.message || "量化雷达扫描失败，请检查网络");
    } finally {
      setLoading(false);
    }
  };

  const handleNavigateToStock = (code: string, name: string) => {
    navigate(`/stock?q=${encodeURIComponent(code + " " + name)}`);
  };

  const data = result?.quantVaneData;

  const renderQuantCard = (stock: QuantVaneStock, idx: number) => {
    const isBuy = stock.direction === 'Buy';
    return (
      <div 
        key={idx} 
        onClick={() => handleNavigateToStock(stock.code, stock.name)}
        className="bg-white border border-slate-100 p-4 rounded-xl hover:shadow-md transition-all cursor-pointer group relative flex flex-col items-center justify-center text-center"
      >
        <div className="font-bold text-slate-800 text-sm mb-1 group-hover:text-indigo-600 transition-colors">
          {stock.name}
        </div>
        <div className={`px-2 py-0.5 rounded text-[10px] font-black tracking-tight ${isBuy ? 'bg-rose-500 text-white' : 'bg-emerald-500 text-white'}`}>
          {isBuy ? '净买 ' : '净卖 '}{stock.net_amount}
        </div>
        <div className="absolute right-1 top-1 opacity-0 group-hover:opacity-100 transition-opacity">
           <ChevronRight className="w-3 h-3 text-slate-300" />
        </div>
      </div>
    );
  };

  const renderSection = (title: string, icon: React.ReactNode, stocks: QuantVaneStock[]) => {
    if (!stocks || stocks.length === 0) return null;
    return (
      <div className="bg-slate-50/50 rounded-2xl p-6 border border-slate-100">
        <div className="flex items-center justify-between mb-6">
           <div className="flex items-center gap-2">
              <div className="p-1.5 bg-white rounded-lg shadow-sm border border-slate-100">
                {icon}
              </div>
              <h3 className="font-black text-slate-800 tracking-tight">{title}</h3>
           </div>
           <ChevronRight className="w-4 h-4 text-slate-300" />
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-3">
          {stocks.map((s, i) => renderQuantCard(s, i))}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-7xl mx-auto pb-20">
      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 p-8 md:p-12 relative overflow-hidden">
        <div className="absolute right-0 top-0 h-full w-1/3 bg-gradient-to-l from-indigo-50 to-transparent pointer-events-none"></div>
        <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-10">
          <div className="flex-1">
            <div className="flex items-center gap-3 mb-4">
               <div className="p-3 bg-rose-600 rounded-2xl text-white shadow-xl shadow-rose-100">
                  <Radio className="w-8 h-8 animate-pulse" />
               </div>
               <h2 className="text-3xl font-black text-slate-800 tracking-tight">量化席位雷达</h2>
            </div>
            <p className="text-slate-500 text-base max-w-2xl font-medium mb-8 leading-relaxed">
              根据您的反馈，本雷达已**硬核对齐龙虎榜真实席位数据**。专门审计量化基金（量化打板、量化抢筹）的最新净买入额。
            </p>
            <div className="flex flex-wrap gap-3">
              <span className="px-4 py-1.5 bg-rose-50 border border-rose-100 rounded-xl text-rose-700 text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                <Flame className="w-3.5 h-3.5" /> 龙虎榜真实数据
              </span>
              <span className="px-4 py-1.5 bg-indigo-50 border border-indigo-100 rounded-xl text-indigo-700 text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                <UserCheck className="w-3.5 h-3.5" /> 量化席位锁死
              </span>
            </div>
