import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult, ModelProvider, MarketType } from "../types";

const quantVaneSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    scan_time: { type: Type.STRING },
    overall_mood: { type: Type.STRING },
    // 全市场 Top 合力标的池
    top_synergy_pool: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          code: { type: Type.STRING },
          net_amount: { type: Type.STRING },
          direction: { type: Type.STRING, enum: ['Buy', 'Sell'] },
          intensity_score: { type: Type.NUMBER },
          logic: { type: Type.STRING }
        },
        required: ["name", "code", "net_amount", "direction"]
      }
    },
    quant_boarding_list: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          code: { type: Type.STRING },
          net_amount: { type: Type.STRING },
          direction: { type: Type.STRING, enum: ['Buy', 'Sell'] },
          logic: { type: Type.STRING }
        },
        required: ["name", "code", "net_amount", "direction"]
      }
    },
    quant_grabbing_list: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          code: { type: Type.STRING },
          net_amount: { type: Type.STRING },
          direction: { type: Type.STRING, enum: ['Buy', 'Sell'] },
          logic: { type: Type.STRING }
        },
        required: ["name", "code", "net_amount", "direction"]
      }
    },
    risk_warning: { type: Type.STRING }
  },
  required: ["scan_time", "overall_mood", "top_synergy_pool", "quant_boarding_list", "quant_grabbing_list", "risk_warning"]
};

export const fetchQuantClusterAnalysis = async (market: MarketType, apiKey: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN');

  const prompt = `
    【硬核指令：量化基金标的池全量审计】
    今日日期: ${dateStr}。作为首席量化研究员，利用 googleSearch 检索 ${market} 市场今日最新的【龙虎榜 (Dragon-Tiger List)】数据，重点锁定标记为“量化基金”或“机构专用（量化）”的席位。

    [重点任务]：
    1. **扩充标的数量**：不要只给我板块！请根据龙虎榜实测数据，挖掘至少 30-40 只具体的量化介入标的。
    2. **分类映射**：
       - **量化基金总榜 (top_synergy_pool)**：综合净买入额最高的 15 只个股。
       - **量化打板 (quant_boarding_list)**：今日涨停且量化席位净买入显著的 10 只以上个股。
       - **量化抢筹 (quant_grabbing_list)**：股价处于放量上涨、但非涨停且量化资金净买入额较大的 10 只以上个股。
    3. **数值真值**：必须准确提取龙虎榜快报中的【净买额】（例如：净买 1.49亿、净买 9059.9万）。

    [输出要求]：
    - 语言全中文，严格遵守 JSON Schema 格式。
    - 确保每个 category 下的标的数量尽可能多，形成一个“标的池”。
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: quantVaneSchema
    }
  });

  const parsed = JSON.parse(response.text || "{}");
  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    quantVaneData: parsed,
    market
  };
};

