const quantVaneSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    scan_time: { type: Type.STRING },
    data_freshness: { type: Type.STRING, description: "数据时效描述：如'实时早盘'、'午间汇总'、'盘后全量'" },
    overall_mood: { type: Type.STRING },
    top_synergy_pool: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          code: { type: Type.STRING },
          net_amount: { type: Type.STRING },
          time_slot: { type: Type.STRING, description: "动作发生时间段：如'09:45早盘起跳'" },
          direction: { type: Type.STRING, enum: ['Buy', 'Sell'] },
          intensity_score: { type: Type.NUMBER },
          logic: { type: Type.STRING }
        },
        required: ["name", "code", "net_amount", "direction"]
      }
    },
    quant_boarding_list: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          code: { type: Type.STRING },
          net_amount: { type: Type.STRING },
          direction: { type: Type.STRING, enum: ['Buy', 'Sell'] },
          logic: { type: Type.STRING }
        },
        required: ["name", "code", "net_amount", "direction"]
      }
    },
    quant_grabbing_list: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          code: { type: Type.STRING },
          net_amount: { type: Type.STRING },
          direction: { type: Type.STRING, enum: ['Buy', 'Sell'] },
          logic: { type: Type.STRING }
        },
        required: ["name", "code", "net_amount", "direction"]
      }
    },
    risk_warning: { type: Type.STRING }
  },
  required: ["scan_time", "data_freshness", "overall_mood", "top_synergy_pool", "quant_boarding_list", "quant_grabbing_list", "risk_warning"]
};

export const fetchQuantClusterAnalysis = async (market: MarketType, apiKey: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });
  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN');
  const hour = now.getHours();

  // 核心逻辑：根据时间点切换检索任务
  let timeInstruction = "";
  if (hour < 13) {
    timeInstruction = `当前为上午交易时段。请重点检索【早盘(9:30-11:30)分时异动快讯】、实时资金流入榜单及各大财经网站的【午评量化动向】。`;
  } else if (hour < 16) {
    timeInstruction = `当前为下午交易时段。请重点检索【早盘(上午)已形成的量化抱团结果】、及午后正在爆发的异动标的。如果龙虎榜未出，优先审计全天成交额中的量价异常。`;
  } else {
    timeInstruction = `当前已收盘。请检索今日全天【最终龙虎榜量化席位】数据，进行全量合力审计。`;
  }

  const prompt = `
    【指令：量化实时/准实时席位雷达审计】
    今日日期: ${dateStr}。${timeInstruction}

    [任务要求]：
    1. **解决延迟**：不要只等龙虎榜！通过 googleSearch 检索各大券商研报、财经快讯中提到的“量化私募活跃度”、“早盘量价共振”数据。
    2. **特定审计**：寻找在上午盘中，成交量呈现阶梯式放大且换手率平稳的标的（典型的量化吸筹特征）。
    3. **分类映射**：
       - **top_synergy_pool**：全市场截止目前（${now.toLocaleTimeString()}）合力最强的标的。
       - **quant_boarding_list**：截止目前封板或尝试封板的量化重仓股。
       - **quant_grabbing_list**：上午活跃度极高、疑似抢筹的非封板股。
    4. **数据属性**：在 time_slot 字段中明确标注这些标的是在“早盘启动”还是“午后异动”。

    [输出要求]：
    - 语言全中文，严格遵守提供的 JSON Schema 格式。
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: quantVaneSchema
    }
  });

  const parsed = JSON.parse(response.text || "{}");
  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    quantVaneData: parsed,
    market
  };
};

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ModelProvider, MarketType, AnalysisResult, QuantVaneStock } from '../types';
import { fetchQuantClusterAnalysis } from '../services/quantService';
import { Radio, Loader2, Search, ArrowRight, Zap, Flame, ShieldCheck, Activity, UserCheck, ShieldAlert, Target, Info, Sparkles, TrendingUp, Gauge, RefreshCw, BarChart3, Globe, ChevronRight, LayoutGrid, ListFilter, Clock, History } from 'lucide-react';

interface QuantVaneProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: any;
  onOpenSettings: () => void;
}

export const QuantVane: React.FC<QuantVaneProps> = ({ currentModel, currentMarket, settings, onOpenSettings }) => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [elapsed, setElapsed] = useState(0);

  useEffect(() => {
    let interval: any;
    if (loading) {
      setElapsed(0);
      interval = setInterval(() => setElapsed(p => p + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleScan = async () => {
    const apiKey = settings.geminiKey || process.env.API_KEY;
    if (!apiKey) {
      onOpenSettings();
      return;
    }
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await fetchQuantClusterAnalysis(currentMarket, apiKey);
      setResult(data);
    } catch (err: any) {
      setError(err.message || "量化雷达扫描失败，请检查网络");
    } finally {
      setLoading(false);
    }
  };

  const handleNavigateToStock = (code: string, name: string) => {
    navigate(`/stock?q=${encodeURIComponent(code + " " + name)}`);
  };

  const data = result?.quantVaneData as any;

  const renderCompactStockCard = (stock: any, idx: number) => {
    const isBuy = stock.direction === 'Buy' || !stock.direction;
    return (
      <div 
        key={idx} 
        onClick={() => handleNavigateToStock(stock.code, stock.name)}
        className="bg-white border border-slate-100 p-3 sm:p-4 rounded-xl hover:border-indigo-400 hover:shadow-lg transition-all cursor-pointer group relative flex flex-col items-center justify-center text-center shadow-sm"
      >
        <div className="font-black text-slate-800 text-sm mb-1 group-hover:text-indigo-600 transition-colors truncate w-full px-1">
          {stock.name}
        </div>
        {stock.time_slot && (
          <div className="text-[8px] text-slate-400 font-bold mb-1.5 flex items-center gap-1">
            <Clock className="w-2 h-2" /> {stock.time_slot}
          </div>
        )}
        <div className={`w-full py-1 rounded text-[10px] font-black tracking-tighter ${isBuy ? 'bg-rose-500 text-white' : 'bg-emerald-500 text-white'}`}>
          {isBuy ? '净买 ' : '净卖 '}{stock.net_amount}
        </div>
        <div className="mt-1 opacity-0 group-hover:opacity-100 transition-opacity flex items-center gap-1 text-[8px] text-slate-400 font-bold uppercase">
           诊断详情 <ChevronRight className="w-2.5 h-2.5" />
        </div>
      </div>
    );
  };

  const renderSection = (title: string, icon: React.ReactNode, stocks: QuantVaneStock[], subtitle?: string) => {
    if (!stocks || stocks.length === 0) return null;
    return (
      <div className="bg-white rounded-[2.5rem] p-8 border border-slate-200 shadow-sm">
        <div className="flex items-center justify-between mb-8">
           <div className="flex items-center gap-3">
              <div className="p-2.5 bg-slate-50 rounded-xl border border-slate-100 shadow-sm">
                {icon}
              </div>
              <div>
                <h3 className="font-black text-slate-800 text-xl tracking-tight">{title}</h3>
                {subtitle && <p className="text-[10px] text-slate-400 font-bold uppercase mt-0.5 tracking-widest">{subtitle}</p>}
              </div>
           </div>
           <div className="flex items-center gap-2 px-3 py-1 bg-slate-50 rounded-full border border-slate-200">
              <span className="text-[10px] font-black text-slate-400">POOL:</span>
              <span className="text-xs font-black text-indigo-600">{stocks.length}</span>
           </div>
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-3 sm:gap-4">
          {stocks.map((s, i) => renderCompactStockCard(s, i))}
        </div>
      </div>
    );
  };

