                 ))}
              </tbody>
           </table>
        </div>

        <div className="flex flex-col sm:flex-row justify-end items-center gap-4 border-t border-slate-100 pt-6">
           <div className="flex items-center gap-2 bg-slate-50 p-1 rounded-lg border border-slate-200">
