           if (item.id !== itemId) return item;
           const states = ['pending', 'completed', 'skipped', 'failed'];
           const nextIndex = (states.indexOf(item.status) + 1) % states.length;
           return { ...item, status: states[nextIndex] as any };
         })
       };
    }));
  };

